import React from 'react';
import { Users, Scale, BookOpen, Code } from 'lucide-react';

const Team: React.FC = () => {
  const teamMembers = [
    {
      icon: <Scale className="w-8 h-8" />,
      title: "Legal Expert Panel",
      description: "Seasoned attorneys and judges crafting authentic scenarios"
    },
    {
      icon: <BookOpen className="w-8 h-8" />,
      title: "Educational Specialists",
      description: "Pedagogy experts designing effective learning pathways"
    },
    {
      icon: <Code className="w-8 h-8" />,
      title: "Tech Innovators",
      description: "Developers creating immersive simulation environments"
    },
    {
      icon: <Users className="w-8 h-8" />,
      title: "User Experience Designers",
      description: "Creating intuitive interfaces for seamless learning"
    }
  ];

  return (
    <section className="py-16 bg-white">
      <div className="container mx-auto px-4">
        <div className="text-center max-w-3xl mx-auto mb-16">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-6">
            Meet Our Visionary Team
          </h2>
          <p className="text-xl text-gray-600">
            CourtCraft is built by a diverse team of legal experts, educators, and technologists.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {teamMembers.map((member, index) => (
            <div 
              key={index} 
              className="bg-gray-50 rounded-xl p-8 text-center hover:shadow-md transition duration-300 border border-gray-100"
            >
              <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 mx-auto mb-6">
                {member.icon}
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-3">{member.title}</h3>
              <p className="text-gray-600">{member.description}</p>
            </div>
          ))}
        </div>

        <div className="mt-16 bg-gradient-to-br from-blue-50 to-indigo-50 rounded-2xl p-8 md:p-12">
          <div className="max-w-4xl mx-auto text-center">
            <h3 className="text-2xl md:text-3xl font-bold text-gray-900 mb-6">
              Be the First to Experience CourtCraft
            </h3>
            <p className="text-lg text-gray-600 mb-8 max-w-2xl mx-auto">
              Join our exclusive mailing list to receive updates, early access invitations, and special launch offers.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 max-w-xl mx-auto">
              <input 
                type="email" 
                placeholder="Enter your email" 
                className="flex-1 px-6 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              />
              <button className="bg-indigo-600 text-white px-8 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium whitespace-nowrap">
                Notify Me at Launch
              </button>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Team;
